<template>
  <div class="app-shell">
    <aside class="sidebar card"><div><div class="eyebrow">Campus Repair Console</div><h2>{{ roleLabel(authState.user?.role) }}</h2><p class="subtle">{{ authState.user?.realName }} · {{ authState.user?.username }}</p></div><nav class="nav-list"><button v-for="item in tabs" :key="item.key" class="nav-item" :class="{ active: activeTab===item.key }" @click="activeTab=item.key"><span>{{ item.icon }}</span>{{ item.label }}</button></nav><button class="btn btn-ghost" @click="openPasswordDialog">修改密码</button><button class="btn btn-ghost" @click="logout">退出登录</button></aside>
    <main class="content-grid">
      <section class="hero card"><div><div class="eyebrow">Reporter Hub</div><h1>报修用户闭环工作台</h1><p class="subtle">覆盖提交、追踪、补充说明、历史评价与消息联动跳转。</p></div><div class="hero-metrics"><div class="hero-chip">消息 {{ unreadCount }}</div></div></section>
      <section v-if="activeTab==='submit'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Reporter</div><h3>自然语言报修提交</h3></div><button class="btn btn-ghost" @click="loadReporter">刷新</button></div><div class="notice-card"><strong>填写建议</strong><p class="subtle">请尽量包含：具体位置、设施或类别、故障现象、紧急程度、方便维修时间。这样大模型能更准确解析并自动派单。</p><p class="subtle">推荐格式：地点 + 设备 + 问题 + 影响程度 + 可上门时间。</p><p class="subtle">示例：呈贡校区楠苑6栋A座302宿舍空调漏水，地面已经有积水，今晚八点以后人在宿舍，希望尽快维修。</p></div><label class="field"><span>报修描述</span><textarea v-model="reportForm.rawText" rows="6" placeholder="请写清：具体位置、故障设备、故障现象、紧急程度、方便维修时间。例如：文汇楼1栋302教室墙面插座断电，明天上午有课前需要恢复供电。"/></label><label class="field"><span>联系电话</span><input v-model.trim="reportForm.contactPhone" placeholder="13912345678"/></label><div class="cluster"><button class="btn btn-primary" :disabled="loading.submit" @click="submitTicket">{{ loading.submit?'提交中...':'提交报修' }}</button><span v-if="feedback.submit" class="feedback feedback-success">{{ feedback.submit }}</span></div></section>
      <section v-if="activeTab==='track'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Reporter</div><h3>报修进度追踪</h3></div><button class="btn btn-ghost" @click="loadReporter">刷新</button></div><div v-if="tickets.length" class="table-wrap"><table><thead><tr><th>工单号</th><th>位置</th><th>故障</th><th>状态</th><th>时间</th><th></th></tr></thead><tbody><tr v-for="item in tickets" :key="item.ticketId"><td>{{ item.ticketNo }}</td><td>{{ item.locationText||'待解析' }}</td><td>{{ item.faultDesc||'原始文本待解析' }}</td><td><StatusPill :label="item.status"/></td><td>{{ formatTime(item.submittedAt) }}</td><td><div class="action-grid"><button class="btn btn-ghost" @click="viewTicket(item.ticketId)">详情</button><button v-if="item.status==='已完成'" class="btn btn-primary" @click="openEvaluateModal(item.ticketId)">评价</button></div></td></tr></tbody></table></div><EmptyState v-else title="暂无报修记录" text="先提交一条自然语言报修。"/></section>
      <section v-if="activeTab==='supplement'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Reporter</div><h3>补充信息 / 回问确认</h3></div><button class="btn btn-ghost" @click="loadReporter">刷新工单</button></div><select v-model="supplementForm.ticketId"><option value="">请选择工单</option><option v-for="item in tickets" :key="item.ticketId" :value="item.ticketId">{{ item.ticketNo }} · {{ item.status }}</option></select><label class="field"><span>补充说明</span><textarea v-model="supplementForm.supplementText" rows="4" placeholder="补充位置、故障现象、可上门时间等信息"/></label><label class="field"><span>更新联系电话（可选）</span><input v-model.trim="supplementForm.contactPhone" placeholder="13800000000"/></label><button class="btn btn-primary" @click="submitSupplement">提交补充信息</button></section>
      <section v-if="activeTab==='evaluations'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Reporter</div><h3>评价详情 / 历史评价</h3></div><button class="btn btn-ghost" @click="loadEvaluations">刷新</button></div><div v-if="evaluations.length" class="table-wrap"><table><thead><tr><th>工单号</th><th>评分</th><th>评价内容</th><th>状态</th><th>时间</th></tr></thead><tbody><tr v-for="item in evaluations" :key="item.ticketId"><td>{{ item.ticketNo }}</td><td>{{ item.score ?? '-' }}</td><td>{{ item.comment || '未填写文字评价' }}</td><td><StatusPill :label="item.ticketStatus"/></td><td>{{ formatTime(item.evaluatedAt) }}</td></tr></tbody></table></div><EmptyState v-else title="暂无评价记录" text="已评价工单会出现在这里。"/></section>
      <section v-if="activeTab==='messages'" class="card panel stack-lg"><div class="section-head"><div><div class="eyebrow">Reporter</div><h3>消息中心</h3></div><button class="btn btn-ghost" @click="loadMessages">刷新</button></div><div v-if="messages.length" class="message-list"><article v-for="msg in messages" :key="msg.id" class="message-card" :class="{ 'message-card--unread': msg.isRead===0 }"><div><strong>{{ msg.title }}</strong><p class="subtle">{{ msg.content }}</p><small>{{ formatTime(msg.createdAt) }}</small></div><button class="btn btn-ghost" @click="openMessage(msg)">联动工单</button></article></div><EmptyState v-else title="暂无消息" text="状态更新后会在这里收到通知。"/></section>
      <section class="card panel stack-lg" ref="detailPanel"><div class="section-head"><div><div class="eyebrow">Ticket Detail</div><h3>当前工单详情</h3></div><button v-if="ticketDetail" class="btn btn-ghost" @click="activeTab='track'">回到工单列表</button></div><p v-if="feedback.global" class="feedback feedback-success">{{ feedback.global }}</p><p v-if="feedback.error" class="feedback feedback-error">{{ feedback.error }}</p><div v-if="ticketDetail" class="detail-board"><div><span>工单号</span><strong>{{ ticketDetail.ticketNo }}</strong></div><div><span>状态</span><StatusPill :label="ticketDetail.status"/></div><div><span>位置</span><strong>{{ ticketDetail.locationText||'待解析' }}</strong></div><div><span>故障描述</span><strong>{{ ticketDetail.faultDesc||ticketDetail.rawText }}</strong></div><div><span>紧急度</span><strong>{{ ticketDetail.urgencyLevel||'-' }}</strong></div><div><span>联系方式</span><strong>{{ ticketDetail.contactMasked||'-' }}</strong></div><div><span>提交时间</span><strong>{{ formatTime(ticketDetail.submittedAt) }}</strong></div><div><span>维修结果</span><strong>{{ ticketDetail.repairResult||'-' }}</strong></div><div><span>评价</span><strong>{{ ticketDetail.evaluationScore ? (ticketDetail.evaluationScore+'分 '+(ticketDetail.evaluationComment||'')) : '-' }}</strong></div></div><div v-if="ticketDetail" class="cluster"><button v-if="ticketDetail.status==='已完成'" class="btn btn-primary" @click="openEvaluateModal(ticketDetail.ticketId)">提交评价</button><button class="btn btn-ghost" @click="activeTab='evaluations'">查看历史评价</button></div><EmptyState v-else title="尚未查看工单详情" text="在列表或消息中点击即可查看。"/></section>
      <div v-if="evalModal.open" class="modal-backdrop" @click.self="closeEvalModal"><section class="modal-card card"><div class="section-head"><h3>提交维修评价</h3><button class="btn btn-ghost" @click="closeEvalModal">关闭</button></div><form class="stack-lg" @submit.prevent="submitEvaluation"><label class="field"><span>评分</span><select v-model.number="evalForm.score"><option v-for="s in [5,4,3,2,1]" :key="s" :value="s">{{ s }} 分</option></select></label><label class="field"><span>评价内容</span><textarea v-model.trim="evalForm.comment" rows="4" placeholder="请填写服务态度、维修结果等评价"/></label><button class="btn btn-primary" type="submit">提交评价</button></form></section></div>
    </main>
  </div>
</template>

<script setup>
import { nextTick, onMounted, reactive, ref } from 'vue'
import { useRouter } from 'vue-router'
import http,{ unwrap } from '../api'
import { authState, clearAuth } from '../store/auth'
import { formatTime, roleLabel } from '../utils'
import StatusPill from './StatusPill.vue'
import EmptyState from './EmptyState.vue'
const router=useRouter(),activeTab=ref('submit'),tickets=ref([]),evaluations=ref([]),messages=ref([]),ticketDetail=ref(null),unreadCount=ref(0),detailPanel=ref(null)
const tabs=[{key:'submit',label:'提交报修',icon:'✦'},{key:'track',label:'进度追踪',icon:'↗'},{key:'supplement',label:'补充信息',icon:'＋'},{key:'evaluations',label:'历史评价',icon:'★'},{key:'messages',label:'消息中心',icon:'✉'}]
const reportForm=reactive({rawText:'',contactPhone:''}),supplementForm=reactive({ticketId:'',supplementText:'',contactPhone:''}),loading=reactive({submit:false}),feedback=reactive({submit:'',global:'',error:''}),evalModal=reactive({open:false,ticketId:null}),evalForm=reactive({score:5,comment:'处理及时，服务很好'})
const reset=()=>{feedback.submit='';feedback.global='';feedback.error=''},closeEvalModal=()=>{evalModal.open=false;evalModal.ticketId=null},logout=()=>{clearAuth();router.push('/login')}
async function openPasswordDialog(){const oldPassword=window.prompt('请输入原密码');if(oldPassword===null)return;const newPassword=window.prompt('请输入新密码（至少6位）');if(newPassword===null)return;const confirmPassword=window.prompt('请再次输入新密码');if(confirmPassword===null)return;if(newPassword!==confirmPassword){feedback.error='两次输入的新密码不一致';return}await safeRun(async()=>{await http.post('/auth/password',{oldPassword,newPassword});clearAuth();router.push('/login')},'密码修改成功，请重新登录')}
async function safeRun(task,msg=''){reset();try{await task();if(msg)feedback.global=msg}catch(err){feedback.error=err.message||'操作失败'}}
async function loadReporter(){tickets.value=unwrap(await http.get('/tickets/my?page=1&size=20')).records||[];await loadMessages()}
async function loadEvaluations(){evaluations.value=unwrap(await http.get('/tickets/my/evaluations?page=1&size=20')).records||[]}
async function loadMessages(){messages.value=unwrap(await http.get('/messages?page=1&size=20')).records||[];unreadCount.value=unwrap(await http.get('/messages/unread-count')).unreadCount||0}
async function focusDetail(){await nextTick();detailPanel.value?.scrollIntoView({behavior:'smooth',block:'start'})}
async function viewTicket(id){await safeRun(async()=>{ticketDetail.value=unwrap(await http.get(`/tickets/${id}`));await focusDetail()})}
async function startEvaluate(id){await viewTicket(id);await evaluateCurrent()}
async function submitTicket(){loading.submit=true;await safeRun(async()=>{const d=unwrap(await http.post('/tickets',reportForm));feedback.submit=`报修提交成功，工单号：${d.ticketNo}`;reportForm.rawText='';reportForm.contactPhone='';await loadReporter();await viewTicket(d.ticketId);activeTab.value='track'});loading.submit=false}
async function submitSupplement(){if(!supplementForm.ticketId)return feedback.error='请先选择工单';await safeRun(async()=>{await http.post(`/tickets/${supplementForm.ticketId}/supplement`,{supplementText:supplementForm.supplementText,contactPhone:supplementForm.contactPhone});supplementForm.supplementText='';supplementForm.contactPhone='';await loadReporter();await viewTicket(Number(supplementForm.ticketId))},'补充信息已提交')}
async function openEvaluateModal(id){await viewTicket(id);evalModal.ticketId=id;evalForm.score=5;evalForm.comment='处理及时，服务很好';evalModal.open=true}
async function submitEvaluation(){if(!evalModal.ticketId)return;await safeRun(async()=>{await http.post(`/tickets/${evalModal.ticketId}/evaluate`,{score:evalForm.score,comment:evalForm.comment});const id=evalModal.ticketId;closeEvalModal();await loadReporter();await loadEvaluations();await viewTicket(id)},'评价已提交')}
async function evaluateCurrent(){await openEvaluateModal(ticketDetail.value?.ticketId)}
async function openMessage(msg){await safeRun(async()=>{await http.post(`/messages/${msg.id}/read`);if(msg.ticketId){activeTab.value='track';ticketDetail.value=unwrap(await http.get(`/tickets/${msg.ticketId}`));await focusDetail()}await loadMessages()},'已定位到对应工单详情')}
onMounted(async()=>{await loadReporter();await loadEvaluations()})
</script>
